    clean = s.replace(' ', '')
    if not clean:
        return []

    result = []
    start = 0
    balance = 0
    for i, ch in enumerate(clean):
        if ch == '(':
            balance += 1
        elif ch == ')':
            balance -= 1
            if balance < 0:
                raise ValueError("Unbalanced parentheses: extra ')'")
        else:
            # Only parentheses are expected after removing spaces
            raise ValueError(f"Unexpected character '{ch}'")

        if balance == 0:
            # A complete group from start to i
            result.append(clean[start:i+1])
            start = i + 1

    if balance != 0:
        raise ValueError("Unbalanced parentheses: missing ')'")

    return result

